echo "===== 1. 磁盘整体使用情况 =====" && df -h / && echo "" && echo "===== 2. 常见可写目录占用 =====" && du -sh /var/log /var/cache /tmp 2>/dev/null | sort -rh && echo "" && echo "===== 3. 大于50MB的日志文件 =====" && find /var/log -xdev -maxdepth 3 -type f -size +50M -printf '%s %p\n' 2>/dev/null | sort -nr | head -20 && echo "" && echo "===== 4. /tmp 临时文件 =====" && du -sh /tmp 2>/dev/null && echo "" && echo "===== 5. 已轮转日志 =====" && find /var/log -xdev -maxdepth 3 -type f \( -name "*.gz" -o -name "*.old" -o -name "*.[0-9]" \) -print 2>/dev/null | head -20 && echo "" && echo "===== 6. APT 可自动卸载的依赖包数量 =====" && apt-mark showauto 2>/dev/null | wc -l && echo "" && echo "===== 7. snap 缓存 =====" && du -sh /var/lib/snapd/cache 2>/dev/null
